import{_ as a,o as t,c as o,a2 as i}from"./chunks/framework.IwO0Hdn_.js";const u=JSON.parse('{"title":"[UI / PRESENTATION] F-04.1 — Vista de Histórico en Pestaña Dedicada","description":"","frontmatter":{},"headers":[],"relativePath":"backlog/F-04.1_vista_historico_pestana.md","filePath":"backlog/F-04.1_vista_historico_pestana.md","lastUpdated":null}'),s={name:"backlog/F-04.1_vista_historico_pestana.md"};function r(d,e,n,c,l,h){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="ui-presentation-f-04-1-—-vista-de-historico-en-pestana-dedicada" tabindex="-1">[UI / PRESENTATION] F-04.1 — Vista de Histórico en Pestaña Dedicada <a class="header-anchor" href="#ui-presentation-f-04-1-—-vista-de-historico-en-pestana-dedicada" aria-label="Permalink to &quot;[UI / PRESENTATION] F-04.1 — Vista de Histórico en Pestaña Dedicada&quot;">​</a></h1><p><strong>Épica:</strong> EPIC-04 — Histórico de Logs Archivados</p><h2 id="🏷️-categoria" tabindex="-1">🏷️ Categoría <a class="header-anchor" href="#🏷️-categoria" aria-label="Permalink to &quot;🏷️ Categoría&quot;">​</a></h2><p><strong>Categoría:</strong> <code>UI / Presentation</code><strong>Impacta en:</strong> Equipo Frontend (Livewire/Blade)</p><h2 id="📦-dependencias" tabindex="-1">📦 Dependencias <a class="header-anchor" href="#📦-dependencias" aria-label="Permalink to &quot;📦 Dependencias&quot;">​</a></h2><blockquote><p>Backlogs que deben estar <strong>completados</strong> antes de implementar esta feature.</p></blockquote><table tabindex="0"><thead><tr><th>Backlog</th><th>Motivo</th></tr></thead><tbody><tr><td><a href="./F-03.2_archivar_historico.html">F-03.2</a></td><td>Al menos un log archivado existente — el archivado es el origen de los datos del histórico</td></tr><tr><td><a href="./F-00.3_layout_navegacion.html">F-00.3</a></td><td>Nav con enlace &#39;Histórico&#39; activo y layout base disponible</td></tr><tr><td><a href="./F-05.4_api_rest_crud.html">F-05.4</a></td><td>Ruta <code>GET /historico</code> definida en <code>routes/web.php</code></td></tr></tbody></table><p><strong>Prioridad:</strong> <code>Must</code></p><hr><p><strong>Descripción:</strong> Como administrador del sistema Quiero acceder al histórico de logs archivados desde una sección o pestaña separada del dashboard activo Para mantener una separación clara entre lo que requiere atención y lo que ya está resuelto</p><p><strong>Criterios de Aceptación (Checklist):</strong></p><ul><li>[ ] <strong>Escenario 1 (Navegación):</strong> Dado que estoy en el dashboard de logs activos, cuando pulso la pestaña &quot;Histórico&quot;, entonces navego a la vista de logs archivados sin perder los datos del dashboard activo.</li><li>[ ] <strong>Escenario 2 (Indicador visual):</strong> Dado que estoy en la vista de histórico, cuando observo la navegación, entonces hay un indicador visual (pestaña activa, clase CSS) que me indica en qué sección estoy.</li><li>[ ] <strong>Escenario 3 (Sin mezcla):</strong> Dado que estoy en la vista de histórico, cuando navego por él, entonces no aparece ningún log activo (solo registros archivados de la tabla <code>archived_logs</code>).</li><li>[ ] <strong>Requisito Técnico:</strong> Ruta web <code>GET /historico</code> con componente Livewire <code>ArchivedLogsTable</code>. Reutiliza la estructura de filtros de F-02.x con el mismo patrón <code>#[Url]</code> (queryString) aplicado sobre <code>archived_logs</code>.</li></ul>',12)])])}const g=a(s,[["render",r]]);export{u as __pageData,g as default};
